const client = $input.first().json;

const isActive = String(client.aktywny || '').toUpperCase().trim();
if (isActive !== 'TRUE' && isActive !== '1' && isActive !== 'TAK') {
  return [{ json: { __skip: true, powod: 'nieaktywny', klient: client.nazwa } }];
}

if (!client.spreadsheet_id || !client.clickup_lista_id) {
  return [{ json: { __skip: true, powod: 'brak spreadsheet_id lub clickup_lista_id', klient: client.nazwa } }];
}

const MONTHS_PL = [
  'STYCZEŃ','LUTY','MARZEC','KWIECIEŃ',
  'MAJ','CZERWIEC','LIPIEC','SIERPIEŃ',
  'WRZESIEŃ','PAŹDZIERNIK','LISTOPAD','GRUDZIEŃ'
];

const now = new Date();
const sheetName = `${MONTHS_PL[now.getMonth()]} CONTENT CALENDAR`;

console.log(`✅ Klient: ${client.nazwa} → ${sheetName}`);

return [{
  json: {
    __skip:         false,
    klientId:       String(client.klient_id || ''),
    klientNazwa:    String(client.nazwa || ''),
    spreadsheetId:  String(client.spreadsheet_id || '').trim(),
    clickupListaId: String(client.clickup_lista_id || '').trim(),
    sheetName
  }
}];

